PRAGMA foreign_keys = ON;

-- Часть 15 из 28. Существующие тайтлы не перезаписываются.

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989493","title":"Black Panther: The Man Without Fear: Fear Itself","author":"David Liss,Francesco Francavilla,Jefte Palo","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001848552/140/b9b2/__Black_Panther_The_Man_Without_Fear_Fear_Itself.jpg","isbn":"9780785152064","publisher":"Marvel","pubDate":"2012","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"The horrifying events of Fear Itself and Spider-Island propel T''Challa through a grueling gauntlet of challenges as Kraven the Hunter, a new Hate Monger and Lady Bullseye come gunning for the lone guardian of Hell''s Kitchen. A series of brutal face-offs with these classic villains sets the stage for the next great Black Panther adversary as the American Panther rises to challenge T''Challa for his mantle! Determined to protect his new home, can even the most dangerous man alive defeat a murderers row of the worst the Marvel Universe has to offer?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":1.5,"review":"","added":9999507,"hdCover":""},{"id":"0989492","title":"Black Panther: The Man Without Fear Volume 1","author":"David Liss","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001847746/140/16ab/David_Liss__Black_Panther_The_Man_Without_Fear_Volume_1.jpg","isbn":"9780785145233","publisher":"","pubDate":"2011","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":2,"review":"","added":9999506,"hdCover":""},{"id":"0989491","title":"Daredevil: Reborn","author":"Andy Diggle","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001260177/140/7af6/Andy_Diggle__Daredevil_Reborn.jpg","isbn":"978-0785151333","publisher":"Marvel","pubDate":"2012","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":2,"review":"","added":9999505,"hdCover":""},{"id":"0989490","title":"Shadowland: After The Fall","author":"","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001261624/140/bfae/bez_avtora__Shadowland_After_The_Fall.jpg","isbn":"","publisher":"Marvel Comics - Back Issue Comic","pubDate":"2010","language":"Английский","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":4,"review":"","added":9999504,"hdCover":""},{"id":"098948f","title":"Shadowland: Power Man","author":"Scott Hanna,Fred Van Lente,Sandu Florea,Mike Perkins,Mahmud Asrar,Dave Sharpe,Frank Martin,Rick Ketchum,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001848056/140/3889/__Shadowland_Power_Man.jpg","isbn":"9780785143970","publisher":"Marvel Comics","pubDate":"2011","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Exploding out of the blood-strewn streets of Shadowland: the all-new, all-different Power Man! Who is he? Why is he one of the few heroes to oppose Daredevil''s rule over Hell''s Kitchen? And what is his connection to Daniel Rand''s School of Thunder dojo and the killer called Bullseye? That''s what Luke Cage and Iron Fist must discover-before the vengeful swords of The Hand find this young mystery man first!  Collecting: Shadowland: Power Man #1-4","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":2,"review":"","added":9999503,"hdCover":""},{"id":"098948e","title":"Shadowland: Blood on the Streets","author":"Энтони Джонстон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001848059/140/ff6d/Entoni_Dzhonston__Shadowland_Blood_on_the_Streets.jpg","isbn":"9780785143994","publisher":"Marvel","pubDate":"2011","language":"Английский","series":"Shadowland","genres":["Комиксы","манга","графические романы"],"annotation":"Striking from the pages of Shadowland, four cult-favorite heroes rise into the spotlight: Silver Sable...Paladin...Misty Knight...The Shroud! Is a rogue faction of Daredevil''s ninjas secretly targeting the mafia? With DD''s dark castle looming over the city, has The Man Without Fear finally lost his mind? This twisted murder mystery ensnares a quartet of vastly different operatives-but will it unite them, or place them in each other''s crosshairs? Can this controversial crew put aside their differences before a war between The Hand and the mob sets New York ablaze? Join Antony Johnston (DAREDEVIL) and Wellinton Alves (THUNDERBOLTS) for a bloody tour down the mean streets of Shadowland!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":2.5,"review":"","added":9999502,"hdCover":""},{"id":"098948d","title":"Shadowland: Street Heroes","author":"Jason Henderson,Джон Лейман","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001848270/140/a903/__Shadowland_Street_Heroes.jpg","isbn":"9780785148876","publisher":"Marvel","pubDate":"2011","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"From the darkness of SHADOWLANDS comes eight blood-soaked tales full of startling revelations and all-out mayhem! Learn what dark tragedy from Colleen Wing''s past binds her to Daredevil''s dark empire. Discover Bullseye''s darkest secrets in the wake of his stint as an Avenger. Find out what exactly caused Elektra to break her vow and return to Daredevil''s side at Shadowland. Then watch as Ghost Rider goes to Japan to battle the Hand. All this plus SPIDER-MAN! Collecting: Shadowland: Daughters Of The Shadow #1-3, Bullseye, Elektra, Ghost Rider, Spider-Man","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":2.5,"review":"","added":9999501,"hdCover":""},{"id":"098948c","title":"Daredevil: Shadowland","author":"Diggle, andy","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001847745/140/1b9c/Diggle_andy__Daredevil_Shadowland.jpg","isbn":"9780785145226","publisher":"Marvel","pubDate":"2011","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"It''s the battle for the soul of Matt Murdock! Daredevil has taken over The Hand, hoping to transform the clan of coldblooded killers into a force for justice. But after returning from Japan, it''s Daredevil who''s changed. He''s locked down Hell''s Kitchen - placing it under martial law and his friends have no choice but to confront him. Foggy Nelson, Dakota North, Power Man and Iron Fist brave the dangers of Shadowland to save Matt Murdock. Meanwhile, Master Izo and Elektra travel to Japan to learn the ninjas'' true plan for Daredevil! Collecting DAREDEVIL (1964) #508-512 and SHADOWLAND: AFTER THE FALL.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":3,"review":"","added":9999500,"hdCover":""},{"id":"098948b","title":"Царство Теней","author":"Энди Диггл,Билли Тэн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001562107/140/d57c/__Tsarstvo_Tenej.jpg","isbn":"","publisher":"Ашет Коллекция, Панини Рус","pubDate":"2016","language":"Русский","series":"Marvel. Официальная коллекция комиксов","genres":["Комиксы","манга","графические романы"],"annotation":"Чтобы защитить Адскую кухню, Дардевил становится во главе зловещего клана ниндзя «Рука». Но к чему приведет этот рискованный поступок? И не превратится ли Дардевил в одного из самых ужасных супезлодеев?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":3,"review":"","added":9999499,"hdCover":""},{"id":"098948a","title":"Shadowland: Moon Knight","author":"Грегг Гервиц","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001848273/140/1b06/Gregg_Gervits__Shadowland_Moon_Knight.jpg","isbn":"9780785148890","publisher":"Marvel","pubDate":"2011","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Who is the Shadow Night? Daredevil, the former defender of Hell''s Kitchen turned leader of the ninja death cult known as the Hand, summons the villainous Profile to take Moon Knight out of the picture for good. To complete his objective, the Profi le enlists the aid of a mysterious figure - a second avatar of Khonshu, the Shadow Knight! Displeased with Moon Knight''s new, less deadly methods, has Khonshu fi nally decided to replace Moon Knight in order to get the blood he requires? With the Shadow Knight hunting him down, Moon Knight must cling to his sanity if he hopes to save Daredevil and himself from the darkness of Shadowland! Plus: The classic first meeting of Moon Knight and Daredevil!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":2.5,"review":"","added":9999498,"hdCover":""},{"id":"0989489","title":"Shadowland: Thunderbolts","author":"Джефф Паркер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001848562/140/d30e/Dzheff_Parker__Shadowland_Thunderbolts.jpg","isbn":"9780785152187","publisher":"Marvel","pubDate":"2011","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Luke Cage heads into Hell''s Kitchen to pull his old friend back from the brink of madness. And if swarming ninjas aren''t enough, he''s become aware of other forces that will make his task even harder. Going against the Warden and the government itself, Cage sends the T-Bolts in to level the playing field. But without his direct guidance, will this squad of killers and criminals make the situation even worse? Find out in the book IGN.com calls \"Impressive...not to be missed.\"  Collecting: Thunderbolts 148-153","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":2.5,"review":"","added":9999497,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
