  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989488","title":"Shadowland: Street Heroes","author":"Джейсон Хендерсон,Джон Лейман","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001848271/140/4a5f/__Shadowland_Street_Heroes.jpg","isbn":"9780785148883","publisher":"Marvel","pubDate":"2011","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Daredevil''s dark transformation and reign over Shadowland has become a major concern. But where do the Marvel street-level heroes fit in? Featuring the Kingpin, Bullseye, Elektra, Ghost Rider, the Daughters of the Shadow and Spider-Man! Collecting SHADOWLAND: DAUGHTERS OF THE SHADOW #1-3, SHADOWLAND: BULLSEYE, SHADOWLAND: ELEKTRA, SHADOWLAND: GHOST RIDER and SHADOWLAND: SPIDER-MAN.-MAN.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":2.5,"review":"","added":9999496,"hdCover":""},{"id":"0989487","title":"Daredevil: The Devil''s Hand","author":"Энди Диггл,Энтони Джонстон","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003212268/140/ee7a/__Daredevil_The_Devil039s_Hand.jpg","isbn":"978-0785141136","publisher":"Marvel","pubDate":"2010","language":"Английский","series":"","genres":[],"annotation":"Meet Daredevil as you''ve NEVER seen him before! The cataclysmic events of issue #500 left Matt in the toughest place of his life - and forced him to make the hardest decision he''s ever made. Now''s the start of a radically different chapter in Daredevil''s adventures with the new creative team of Andy Diggle (Thunderbolts) and Roberto De La Torre (Iron Man) Collects Daredevil: Dark Days & Daredevil #501-505.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":3.5,"review":"","added":9999495,"hdCover":""},{"id":"0989486","title":"Daredevil: Return of the King","author":"Эд Брубейкер,Дэвид Аха","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003212261/140/1148/__Daredevil_Return_of_the_King.jpg","isbn":"978-0785133407","publisher":"Marvel","pubDate":"2009","language":"Английский","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":3,"review":"","added":9999494,"hdCover":""},{"id":"0989485","title":"Daredevil: Lady Bullseye","author":"Эд Брубейкер","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003212259/140/04d8/Ed_Brubejker__Daredevil_Lady_Bullseye.jpg","isbn":"978-0785131816","publisher":"Marvel","pubDate":"2009","language":"Английский","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":2.5,"review":"","added":9999493,"hdCover":""},{"id":"0989484","title":"Daredevil: Cruel and Unusual","author":"Грег Рака,Эд Брубейкер","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003212258/140/3078/__Daredevil_Cruel_and_Unusual.jpg","isbn":"978-0785128892","publisher":"Marvel","pubDate":"2008","language":"Английский","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":3.5,"review":"","added":9999492,"hdCover":""},{"id":"0989483","title":"Daredevil: Hell to Pay, Vol. 2","author":"Эд Брубейкер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003212257/140/7213/Ed_Brubejker__Daredevil_Hell_to_Pay_Vol._2.jpg","isbn":"978-0785128151","publisher":"Marvel","pubDate":"2008","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":4.5,"review":"","added":9999491,"hdCover":""},{"id":"0989482","title":"Человек-паук. Веном","author":"Дэвид Мишлени,Тодд МакФарлан","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000921550/140/d57f/__Chelovekpauk._Venom.jpg","isbn":"ISSN 2304-9057","publisher":"Hachette, Ашет Коллекция, Панини Рус","pubDate":"2014","language":"Русский","series":"Marvel. Официальная коллекция комиксов","genres":["Комиксы","манга","графические романы"],"annotation":"Человек-Паук отверг разумного инопланетного симбиота, служившего ему живым костюмом черного цвета с удивительными способностями. Симбиот был вынужден искать новую жертву и нашел ее в лице Эдди Брока, человека, который столь же сильно ненавидел Паука. Так появился самый страшный враг супергероя. Веном - монстр, обладающий всеми способностями Человека-Паука и жаждующий мести...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":4,"review":"","added":9999490,"hdCover":""},{"id":"0989481","title":"Удивительные Люди Икс. Одаренные","author":"Джосс Уидон, Джон Кассадей","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000810005/140/13b7/Dzhoss_Uidon_Dzhon_Kassadej__Udivitelnye_Lyudi_Iks._Odarennye.jpg","isbn":"ISSN 2304-9057","publisher":"Ашет Коллекция, Ашетт Коллекция, Панини Рус","pubDate":"2014","language":"Русский","series":"Marvel. Официальная коллекция комиксов","genres":["Комиксы","манга","графические романы"],"annotation":"Циклоп и Эмма Фрост воссоздают команду Людей Икс с одной-единственной целью ― поразить мир. Но когда ошеломительная новость о гене мутанта неожиданно взрывает эфир, это может разрушить их планы прежде, чем они успеют что-либо предпринять. И поскольку потребность в лекарстве против мутации становится жизненно необходимой, противостояние Людей Икс с загадочным Ордом, а также встреча с неожиданным союзником и столь же неожиданными противниками ― заставляют их пойти на крайние меры.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":5,"review":"","added":9999489,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989480","title":"Человек-Паук. Возвращение","author":"Джей Майкл Стражински,Джон Ромита-мл.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000797842/140/2c08/__ChelovekPauk._Vozvraschenie.jpg","isbn":"ISSN 2304-9057","publisher":"Marvel, Ашет Коллекция, Ашетт Коллекция, Панини Рус","pubDate":"2014","language":"Русский","series":"Marvel. Официальная коллекция комиксов","genres":["Комиксы","манга","графические романы"],"annotation":"Питер Паркер всю жизнь был одинок. Когда укус радиоактивного паука даровал ему суперспособности, Питер сохранил их в секрете. Он попробовал разбогатеть с помощью обретенных сил ― но это лишь привело к гибели его любимого дяди Бена. Никто не понимал, как тяжело быть супергероем. Но теперь все изменится. Неожиданно появляется таинственный незнакомец, наделенный похожими паучьими способностями. Кто он? Что за силы стоят за ним? И какое древнее зло начало охоту за Питером?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":4,"review":"","added":9999488,"hdCover":""},{"id":"098947f","title":"Daredevil: Hell to Pay, Vol. 1","author":"Эд Брубейкер,Michael Lark","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003212256/140/78fa/__Daredevil_Hell_to_Pay_Vol._1.jpg","isbn":"978-0785124849","publisher":"Marvel","pubDate":"2007","language":"Английский","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":4.5,"review":"","added":9999487,"hdCover":""},{"id":"098947e","title":"Daredevil: The Devil, Inside and Out, Vol. 2","author":"Эд Брубейкер","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003212255/140/aeaa/Ed_Brubejker__Daredevil_The_Devil_Inside_and_Out_Vol._2.jpg","isbn":"978-0785122418","publisher":"Marvel","pubDate":"2007","language":"Английский","series":"","genres":[],"annotation":"Daredevil''s search for the truth leads him out of the country, on a swashbuckling noir adventure that hasn''t been seen in the pages of DD for years! But is this the other DD, or the original? Only time will tell, as the hit new DD creative team of Brubaker and Lark dive straight into their second story. Plus: a special episode focusing on Daredevil''s recently deceased best friend, Foggy Nelson. Did we really know all there is to know about Foggy? What remains hidden in the life of this man, that could still affect Matt Murdock''s fate to this day? Collects Daredevil #88-93.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":4.5,"review":"","added":9999486,"hdCover":""},{"id":"098947d","title":"Daredevil: The Devil, Inside and Out, Vol. 1","author":"Эд Брубейкер","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003212254/140/02cd/Ed_Brubejker__Daredevil_The_Devil_Inside_and_Out_Vol._1.jpg","isbn":"978-0785119883","publisher":"Marvel","pubDate":"2006","language":"Английский","series":"","genres":[],"annotation":"The critically acclaimed, award-winning new creative team of Ed Brubaker and Michael Lark make their explosive debut in a storyline that Daredevil fans will not be able to put down! For the past few years, Matt Murdock''s life has been teetering on the edge of destruction. Now, pushed beyond the limit, Matt finds himself behind the eight ball with no clear way out, the people he calls friends slowly deserting him, and Hell''s Kitchen gradually slipping out of control. The question is, when his back is against the wall, just how far will Daredevil go to get back what is his? Spinning out of the stunning finale of Bendis and Maleev''s ground-breaking run, Brubaker and Lark pick up the billy club and run as hard and as fast as they can to leave their own mark on one of comics'' most enduring legends. Longtime DD fans will not be disappointed! Collects Daredevil #82-87.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":5,"review":"","added":9999485,"hdCover":""},{"id":"098947c","title":"Daredevil: Battlin'' Jack Murdock","author":"Zeb Wells","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001531886/140/dd48/Zeb_Wells__Daredevil_Battlin039_Jack_Murdock.jpg","isbn":"978-0785125341","publisher":"Marvel Comics","pubDate":"2008","language":"","series":"","genres":[],"annotation":"The fire that burns in the chest of Matt Murdock finds its origin in this 4-issue limited series by fan-favorite writer Zeb Wells and international superstar Carmine Di Giandomenico. Learn the story of Daredevil''s father -- the comic-book icon Battlin'' Jack Murdock -- as he boxes four rounds in what is destined to be the last fight of his life. See what leads the man who raised Daredevil to betray his gangland bosses and fight with integrity...even if it means his own death!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":4,"review":"","added":9999484,"hdCover":""},{"id":"098947b","title":"Спаун. Том 2","author":"Грант Моррисон,Тодд МакФарлан","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002607888/140/1a4c/__Spaun._Tom_2.jpg","isbn":"9785919961321","publisher":"XL Media","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"В 1992 году перед публикой предстал один из самых незабываемых персонажей комиксов... и он изменил этот мир навсегда.  Спаун не похож на всем известных супергероев. Прежде его звали Эл Симмонс. Он был правительственным агентом США, которого подставили и убили. Воскрешенный в глубинах Ада Симмонс возвращается в Нью-Йорк в облике чудовищного мстителя и встает на защиту обитателей подворотен. Теперь ему предстоит разгадать тайну собственной гибели, сразиться с силами зла, вернувшими его к жизни, и найти новых неожиданных союзников...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":4,"review":"","added":9999483,"hdCover":""},{"id":"098947a","title":"Спаун. Том 1","author":"Фрэнк Миллер,Алан Мур,Нил Гейман,Дейв Сим,Тодд МакФарлан,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001858757/140/2ca5/__Spaun._Tom_1.jpg","isbn":"978-5-91996-092-8","publisher":"XL Media","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"В 1992 году перед публикой предстал один из самых незабываемых персонажей комиксов... и он изменил этот мир навсегда.  Спаун не похож на всем известных супергероев. Прежде его звали Эл Симмонс. Он был правительственным агентом США, которого подставили и убили. Воскрешенный в глубинах Ада Симмонс возвращается в Нью-Йорк в облике чудовищного мстителя и встает на защиту обитателей подворотен. Теперь ему предстоит разгадать тайну собственной гибели, сразиться с силами зла, вернувшими его к жизни, и найти новых, неожиданных союзников...  «Спаун» Тодда МакФарлейна — одна из самых необычных и успешных независимых серий комиксов, и вам наконец-то представился шанс узнать историю этого удивительного героя с самого начала. В эту книгу вошли первые 12 выпусков, написанные лучшими сценаристами комикс-индустрии (Аланом Муром, Нилом Гейманом, Фрэнком Миллером, Дэйвом Симом), а также множество дополнительных материалов: отрывки из интервью, наброски и иллюстрации.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":4,"review":"","added":9999482,"hdCover":""},{"id":"0989479","title":"Daredevil: Redemption","author":"Майкл Гэйдос,Дэвид Хайн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000297730/140/8a10/__Daredevil_Redemption.jpg","isbn":"0785115668","publisher":"Marvel","pubDate":"2005","language":"Английский","series":"","genres":["Детские книги","Комиксы","манга","графические романы"],"annotation":"In the small, God-fearing town of Redemption Valley, a young boy''s body is found dead and mutilated. Is it a ritualistic killing? The local bad boy, Joel Flood, is arrested and put in jail. A black-garbed, \"devil-worshipping\" metalhead, he must be guilty... or is he? Enter attorney and super-hero Matt Murdock, brought in to save the troubled teen from what looks like a witch-hunt by an outraged community desperate for justice... and the death penalty. This may be the most important case of Matt''s career. A loss means justice denied and certain death for his client. Collects Daredevil: Redemption #1-6.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":4,"review":"","added":9999481,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989478","title":"Веном. Тёмное начало","author":"Зеб Уэллс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002918724/140/18bd/Zeb_Uells__Venom._Tjomnoe_nachalo.jpg","isbn":"978-5-91878-302-3","publisher":"Фантастика Книжный Клуб","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"СИЛА ГНЕВА И МЕСТИ, КАКОЙ НЕ НАЙТИ ВО ВСЕЙ ВСЕЛЕННОЙ MARVEL!  В один ужасный день, когда озлобленный и потерпевший неудачу журналист встретил отвергнутого паразита с другой планеты, появился опаснейший враг Человека-Паука — Веном! Но так ли всё просто? Узрите истинные запутанные первопричины, которые породили вечную ненависть Эдди Брока... и симбиота! Сценарист Зеб Уэллс («Удивительный Человек-Паук») и художник Энджел Медина («Сенсационный Человек-Паук») проливают немного света на сущность одного из темнейших чудовищ вселенной Marvel!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":3.5,"review":"","added":9999480,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
