)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989477","title":"Marvel Knights 20th","author":"Донни Кейтс","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003232975/140/e708/Donni_Kejts__Marvel_Knights_20th.jpg","isbn":"9781302916749","publisher":"Marvel","pubDate":"2019","language":"Английский","series":"","genres":[],"annotation":"In celebration of the legendary imprint founded two decades ago by Marvel''s CCO Joe Quesada, a new crop of talented creators stand poised to tell a groundbreaking story in the hard-hitting Marvel Knights style! In the cemetery, the blind man does not know who he is, or why he has come to this particular grave. He doesn''t know the burly policeman with the wild story who has approached him. Or the strangely intense man who sits in the rear seat of the patrol car, his eyes flashing green. But all that is about to change. Matt Murdock is beginning to remember. In a colorless world without heroes, the spark of light must come from the dark. Together, these individuals face a mystery that can only be unraveled...a threat that can only be challenged...by Knights.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":2,"review":"","added":9999479,"hdCover":""},{"id":"0989476","title":"Сорвиголова. Полное издание. Книга 3","author":"Алекс Малеев,Брайан Майкл Бендис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005461314/140/1258/__Sorvigolova._Polnoe_izdanie._Kniga_3.jpg","isbn":"978-5-04-110030-8","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Перед вами последняя книга легендарной серии, надолго определившей будущее Сорвиголовы. Брайан Майкл Бендис и Алекс Малеев великолепно использовали множество персонажей вселенной Marvel и выстроили цепь событий, которая привела Мэтта Мёрдока к неизбежной развязке! Как долго Дьявол Адской кухни сможет хранить свой секрет и отбиваться от журналистов? Одна публикация в СМИ чуть не разрушила жизнь успешного адвоката, но что он будет делать, когда появится второе разоблачение? А перед этим вы найдёте ответы на следующие вопросы: кто был Кингпином до Кингпина и какие у него были отношения с Сорвиголовой? Что случилось за время, что Мёрдок управлял преступным миром Адской кухни? Хватит ли сил у Человека без страха справиться с потусторонней угрозой, тесно связанной с древним кланом ниндзя? Но все это меркнет в сравнении с грандиозным финалом… ведь УИЛСОН ФИСК ВЕРНУЛСЯ! И он готов разрушить жизнь Мэтта Мёрдока! Лихо закрученный сюжет с неожиданной развязкой, безумно красивый рисунок, жестокие схватки, бесконечные ловушки и обманы, целая россыпь врагов и друзей Мэтта Мёрдока, готовых вступить в схватку за будущие Сорвиголовы, всё это ждёт вас на страницах заключительного тома одной из лучших серий о Дьяволе Адской кухни!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":4.5,"review":"","added":9999478,"hdCover":""},{"id":"0989475","title":"Daredevil: Father","author":"Joe Quesada","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001534785/140/bdce/Joe_Quesada__Daredevil_Father.jpg","isbn":"978-0785119258","publisher":"Marvel Comics","pubDate":"2009","language":"Английский","series":"","genres":["Детские книги","Комиксы","манга","графические романы"],"annotation":"Daredevil legend Joe Quesada crafts a mystery set during the deadliest heat wave in NYC history. A serial killer is on the loose, pushing a city already past its breaking point over the edge, and Daredevil must battle the heat and fear to keep a crumbling Hell''s Kitchen together...by any means necessary!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":4,"review":"","added":9999477,"hdCover":""},{"id":"0989474","title":"Ultimate Daredevil & Elektra","author":"Greg Rucka","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002644885/140/d639/Greg_Rucka__Ultimate_Daredevil_amp_Elektra.jpg","isbn":"9780785110767","publisher":"Marvel","pubDate":"2003","language":"Английский","series":"","genres":[],"annotation":"Wide-eyed Elektra Natchios arrives at Columbia University with a fourth-degree black belt in karate, but her first brush with a campus menace named Trey is nothing compared to the romantic free-fall she plunges into when she meets Matthew Murdock, a blind pre-law student... who is more than he appears.  Collecting: Ultimate Daredevil & Elektra 1-4 & Daredevil 9","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":2.5,"review":"","added":9999476,"hdCover":""},{"id":"0989473","title":"Daredevil/Bullseye: The Target Vol 1","author":"Гленн Фабри,Кевин Смит","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002577201/140/e875/__DaredevilBullseye_The_Target_Vol_1.jpg","isbn":"","publisher":"Marvel Comics","pubDate":"2003","language":"Английский","series":"","genres":[],"annotation":"It has been three years since the death of Karen Page at the hands of Bullseye, and Matt Murdock has been preparing for the anniversary. He has pushed body and powers to their very limit with the plans confronting Bullseye again.  But Bullseye''s been busy, too. He has been honing his skills to greater levels. Now with sharper skills and a new look, he has set his sights on one of New York City''s elite.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":3,"review":"","added":9999475,"hdCover":""},{"id":"0989472","title":"The Boys, Vol. 11: Over the Hill with the Swords of a Thousand Men","author":"Гарт Эннис,Russ Braun","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003404281/140/6c19/__The_Boys_Vol._11_Over_the_Hill_with_the_Swords_of_a_Thousand_Men.jpg","isbn":"978-1606903414","publisher":"Dynamite Entertainment","pubDate":"2012","language":"","series":"The Boys Book Series","genres":["Комиксы","манга","графические романы"],"annotation":"It''s been a long time coming, but Billy Butcher''s revenge on his wife''s killer is about to be realized - if he can only get his hands on the bastard. The Boys prepare for one last terrible battle, as the Homelander finally bites the bullet and sets an army of superheroes against the forces of the United States military. Battle rages at the White House, Frenchie and the Female are unleashed, and Hughie faces his own terrors... while MM, patient to the last, races against time to uncover the greatest and most dreadful secret of Vought-American''s superhero program. Butcher steps willingly into the jaws of death, alone and unafraid: but what he finds waiting for him is beyond even his darkest dreams. The Boys, Vol. 11: Over the Hill with the Swords of a Thousand Men collects issues 60-65 of the hit series The Boys by Garth Ennis, Russ Braun, John McCrea, Keith Burns and Darick Robertson, and features all of the covers by Darick Robertson!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":5,"review":"","added":9999474,"hdCover":""},{"id":"0989471","title":"The Boys, Vol. 10: Butcher, Baker, Candlestickmaker","author":"Дэрик Робертсон,Гарт Эннис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003404280/140/49e7/__The_Boys_Vol._10_Butcher_Baker_Candlestickmaker.jpg","isbn":"978-1606902646","publisher":"Dynamite Entertainment","pubDate":"2012","language":"","series":"The Boys Book Series","genres":["Комиксы","манга","графические романы"],"annotation":"He could have been a very different man. Billy Butcher, leader of The Boys, once had a chance at another life entirely - when the love of a good woman pulled him aside from his dreadful path of violence and despair. This is the story of Billy and Becky, told by the man himself: from the backstreets of London''s East End to the carnage of the Falklands War, from the heights of love to the depths of tragedy. And when he''s done, he''ll be ready ... to finish things once and for all. The Boys, Vol. 10: Butcher, Baker, Candlestickmaker collects issues 1-6 of the hit mini-series, The Boys: Butcher, Baker, Candlestickmaker by Garth Ennis and Darick Robertson, and features all of the covers by Darick Robertson!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":4,"review":"","added":9999473,"hdCover":""},{"id":"0989470","title":"Удивительный Человек-Паук. Мировой уровень. Том 2","author":"Дэн Слотт,Маттео Буффани","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002797198/140/3b23/__Udivitelnyj_ChelovekPauk._Mirovoj_uroven._Tom_2.jpg","isbn":"978-5-04-094070-7","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"ПИТЕР ПАРКЕР ВЫШЕЛ НА МИРОВОЙ УРОВЕНЬ, и его следующая остановка — Китай. Там он узнает, что зловещий Мистер Негатив подчинил двух его давних друзей: любимый фанатами дуэт Плаща и Кинжала!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-11","rating":3,"review":"","added":9999472,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
